use std::collections::HashMap; use crate::core::buffer::Buffer; use crate::core::events::{EditorEvent, EventListener}; use crate::core::io; pub struct EditorAPI { pub buffers: HashMap<String, Buffer>, pub active_buffer: String, pub listeners: Vec<Box<dyn EventListener>>, } impl EditorAPI { pub fn new(initial_name: &str) -> Self { let mut buffers = HashMap::new(); buffers.insert(initial_name.to_string(), Buffer::new()); Self { buffers, active_buffer: initial_name.to_string(), listeners: Vec::new() } } pub fn save_active_buffer(&self, path: &str) -> std::io::Result<()> { io::save_to_file(path, self.buffers.get(&self.active_buffer).unwrap()) } pub fn load_buffer(&mut self, name: &str, path: &str) -> std::io::Result<()> { let buffer = io::load_from_file(path)?; self.buffers.insert(name.to_string(), buffer); Ok(()) } pub fn notify(&self, event: EditorEvent) { for listener in &self.listeners { listener.on_event(event.clone()); } } pub fn add_listener(&mut self, listener: Box<dyn EventListener>) { self.listeners.push(listener); } pub fn get_active_buffer(&mut self) -> &mut Buffer { self.buffers.get_mut(&self.active_buffer).unwrap() } pub fn handle_keypress(&mut self, key: &str) { let buffer = self.get_active_buffer(); match key { "BACKSPACE" => { buffer.undo(); } _ => { buffer.insert_line(0, buffer.lines[0].len(), key); } } self.notify(EditorEvent::TextChanged); } }
impl EditorAPI { pub fn handle_keypress(&mut self, key: &str) { let buffer = self.get_active_buffer(); match key { "BACKSPACE" => { buffer.undo(); } "ENTER" => { buffer.lines.insert(buffer.lines.len(), String::new()); } _ => { buffer.insert_line(0, buffer.lines[0].len(), key); } } self.notify(EditorEvent::TextChanged); } pub fn list_open_buffers(&self) -> Vec<String> { self.buffers.keys().cloned().collect() } } impl EventListener for ConsoleLogger { fn on_event(&self, event: EditorEvent) { match event { EditorEvent::TextChanged => println!("¡Cambio detectado en el buffer!"), } } } struct ConsoleLogger; pub fn setup_default_listeners(api: &mut EditorAPI) { api.add_listener(Box::new(ConsoleLogger)); }
